One possible solution is to create a custom implementation of `PerformInteractiveRebinding` that uses `UniTask`. Here's an example:

```csharp
using System;
using UnityEngine;

public class CustomRebindingOperation : RebindingOperation
{
    private readonly Action<int, int> _action;
    private UniTask<bool> _result;

    public CustomRebindingOperation(int bindingIndex, Action<int, int> action)
        : base(bindingIndex)
    {
        _action = action;
    }

    protected override void Execute()
    {
        _result = UniTask.WhenAll(
            PerformInteractiveRebinding(0, bindingIndex),
            PerformInteractiveRebinding(bindingIndex + 1, 999)
        );

        if (_result.IsCompleted && !_result.Result)
