void UHotPatcher::ProcessChunk(const FString& ChunkPath, const TArray<FString>& NoAssetPaths)
{
    // Chunk paketleme işlemi
    FArchive* ChunkArchive = CreateChunkArchive(ChunkPath);

    for (const FString& AssetPath : AssetPaths)
    {
        if (!IsAssetInNoAssetList(AssetPath, NoAssetPaths))
        {
            AddAssetToChunk(ChunkArchive, AssetPath);
        }
    }

    // Paketleme işlemi
    ChunkArchive->Close();
}

bool UHotPatcher::IsAssetInNoAssetList(const FString& AssetPath, const TArray<FString>& NoAssetPaths)
{
    for (const FString& NoAssetPath : NoAssetPaths)
    {
        if (FPaths::IsParentOrThis(AssetPath, NoAssetPath))
